  1	import * as React from 'react';
  2	import { useSafeK8sWatchResource } from '@odf/core/hooks';
  3	import {
  4	  useODFNamespaceSelector,
  5	  useODFSystemFlagsSelector,
  6	} from '@odf/core/redux';
  7	import { getStorageClusterInNs } from '@odf/core/utils';
  8	import HandleErrorAndLoading from '@odf/shared/error-handler/ErrorStateHandler';
  9	import { useDeepCompareMemoize } from '@odf/shared/hooks/deep-compare-memoize';
 10	import { DeploymentModel, NodeModel } from '@odf/shared/models';
 11	import { getName, getUID } from '@odf/shared/selectors';
 12	import { BlueInfoCircleIcon } from '@odf/shared/status';
 13	import {
 14	  createNode,
 15	  defaultLayoutFactory,
 16	  stylesComponentFactory,
 17	  TopologyDataContext,
 18	  TopologySearchContext,
 19	  TopologyViewLevel,
 20	} from '@odf/shared/topology';
 21	import {
 22	  DeploymentKind,
 23	  NodeKind,
 24	  PodKind,
 25	  StorageClusterKind,
 26	} from '@odf/shared/types';
 27	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 28	import {
 29	  K8sResourceCommon,
 30	  useK8sWatchResource,
 31	} from '@openshift-console/dynamic-plugin-sdk';
 32	import * as _ from 'lodash-es';
 33	import { Link } from 'react-router-dom-v5-compat';
 34	import {
 35	  Button,
 36	  ButtonVariant,
 37	  EmptyState,
 38	  EmptyStateBody,
 39	  EmptyStateIcon,
 40	  Title,
 41	} from '@patternfly/react-core';
 42	import { ArrowCircleLeftIcon, TopologyIcon } from '@patternfly/react-icons';
 43	import {
 44	  useVisualizationController,
 45	  TopologyView,
 46	  VisualizationSurface,
 47	  Visualization,
 48	  VisualizationProvider,
 49	  SELECTION_EVENT,
 50	  TopologyControlBar,
 51	  LabelPosition,
 52	  NodeShape,
 53	  GraphElement,
 54	  defaultControlButtonsOptions,
 55	  createTopologyControlButtons,
 56	} from '@patternfly/react-topology';
 57	import { cephStorageLabel, CREATE_SS_PAGE_URL } from '../../constants';
 58	import {
 59	  nodeResource,
 60	  odfDaemonSetResource,
 61	  odfDeploymentsResource,
 62	  odfPodsResource,
 63	  odfReplicaSetResource,
 64	  odfStatefulSetResource,
 65	  storageClusterResource,
 66	} from '../../resources';
 67	import {
 68	  hasAnyExternalOCS,
 69	  hasAnyInternalOCS,
 70	  hasAnyCeph,
 71	  hasAnyNoobaaStandalone,
 72	} from '../../utils';
 73	import {
 74	  STEP_INTO_EVENT,
 75	  STEP_TO_CLUSTER,
 76	  ZOOM_IN,
 77	  ZOOM_OUT,
 78	} from './constants';
 79	import {
 80	  generateDeploymentsInNodes,
 81	  generateNodesInZone,
 82	  generateStorageClusterGroup,
 83	} from './NodeGenerator';
 84	import TopologySideBar from './sidebar/TopologySideBar';
 85	import { TopologyTopBar } from './TopBar';
 86	import {
 87	  generateNodeDeploymentsMap,
 88	  getTopologyDomain,
 89	  groupNodesByZones,
 90	} from './utils';
 91	import './topology.scss';
 92	
 93	type SideBarProps = {
 94	  onClose: any;
 95	  isExpanded: boolean;
 96	};
 97	
 98	const Sidebar: React.FC<SideBarProps> = ({ onClose, isExpanded }) => {
 99	  const { selectedElement: element } = React.useContext(TopologyDataContext);
100	  const data = element?.getData();
101	  const resource = data?.resource;
102	
103	  return (
104	    <TopologySideBar
105	      resource={resource}
106	      onClose={onClose}
107	      isExpanded={isExpanded}
108	    />
109	  );
110	};
111	
112	type BackButtonProps = {
113	  onClick: () => void;
114	};
115	
116	const MessageButton: React.FC = () => {
117	  const { t } = useCustomTranslation();
118	  const [showMessage, setShowMessage] = React.useState(false);
119	
120	  return (
121	    <div className="odf-topology__message-button">
122	      <BlueInfoCircleIcon />{' '}
123	      {showMessage &&
124	        t('This view is not available for external mode cluster.')}{' '}
125	      <Button
126	        variant={ButtonVariant.link}
127	        isInline
128	        className="odf-topology__show-message-button"
129	        onClick={() => setShowMessage(!showMessage)}
130	      >
131	        {!showMessage ? t('Show message') : t('Hide message')}
132	      </Button>
133	    </div>
134	  );
135	};
136	
137	const BackButton: React.FC<BackButtonProps> = ({ onClick }) => {
138	  const { t } = useCustomTranslation();
139	  return (
140	    <Button
141	      variant={ButtonVariant.plain}
142	      className="odf-topology__back-button"
143	      onClick={onClick}
144	    >
145	      <ArrowCircleLeftIcon /> {t('Back to main view')}
146	    </Button>
147	  );
148	};
149	
150	const TopologyViewComponent: React.FC = () => {
151	  const { t } = useCustomTranslation();
152	  const [selectedIds, setSelectedIds] = React.useState<string[]>([]);
153	  const [currentView, setCurrentView] = React.useState(TopologyViewLevel.NODES);
154	  const controller = useVisualizationController();
155	
156	  const lastNode = React.useRef<string>();
157	
158	  const [isSideBarOpen, setSideBarOpen] = React.useState(false);
159	  const {
160	    nodes,
161	    storageCluster,
162	    deployments,
163	    visualizationLevel,
164	    activeNode,
165	    nodeDeploymentMap,
166	    setSelectedElement,
167	  } = React.useContext(TopologyDataContext);
168	
169	  const onCloseSideBar = React.useCallback(() => {
170	    setSideBarOpen(false);
171	    setSelectedIds([]);
172	  }, []);
173	
174	  React.useEffect(() => {
175	    const selectionHandler = (ids: string[]) => {
176	      const element = controller.getElementById(ids[0]);
177	      if (!!element && !_.has(element.getData(), 'zone')) {
178	        setSelectedElement(element);
179	        setSelectedIds([ids[0]]);
180	        setSideBarOpen(true);
181	      }
182	    };
183	    controller.addEventListener(SELECTION_EVENT, selectionHandler);
184	    controller.addEventListener(STEP_INTO_EVENT, onCloseSideBar);
185	    controller.addEventListener(STEP_TO_CLUSTER, onCloseSideBar);
186	    return () => {
187	      controller.removeEventListener(SELECTION_EVENT, selectionHandler);
188	      controller.removeEventListener(STEP_INTO_EVENT, onCloseSideBar);
189	      controller.removeEventListener(STEP_TO_CLUSTER, onCloseSideBar);
190	    };
191	  }, [controller, setSelectedElement, onCloseSideBar]);
192	
193	  React.useEffect(() => {
194	    const groupedNodes = groupNodesByZones(nodes);
195	    const dataModel = groupedNodes.map(generateNodesInZone);
196	    const flattenedDataModel = _.flatten(dataModel);
197	    const children = flattenedDataModel
198	      .filter((item) => item.type === 'group')
199	      .map((item) => item.id);
200	    const storageClusterGroup = generateStorageClusterGroup(storageCluster);
201	    storageClusterGroup.children = children;
202	    const data = {
203	      nodes: [storageClusterGroup, ...flattenedDataModel],
204	    };
205	    const model = {
206	      graph: {
207	        id: 'g1',
208	        type: 'graph',
209	        layout: 'Cola',
210	      },
211	      ...data,
212	    };
213	    controller.fromModel(model);
214	    // To handle initial render only, keeping array empty
215	    // eslint-disable-next-line react-hooks/exhaustive-deps
216	  }, []);
217	
218	  React.useEffect(() => {
219	    const currentNode = activeNode
220	      ? nodes.find((node) => getName(node) === activeNode)
221	      : nodes[0];
222	
223	    const needsUpdate =
224	      currentView !== visualizationLevel || activeNode !== lastNode.current;
225	    if (activeNode !== lastNode.current) {
226	      lastNode.current = activeNode;
227	    }
228	
229	    if (needsUpdate && TopologyViewLevel.DEPLOYMENTS === visualizationLevel) {
230	      const dataModel = generateDeploymentsInNodes(
231	        currentNode,
232	        nodeDeploymentMap
233	      );
234	      const model = {
235	        graph: {
236	          visualizationLevel,
237	          id: 'g1',
238	          type: 'graph',
239	          layout: 'Cola',
240	        },
241	        nodes: dataModel,
242	      };
243	      controller.fromModel(model, false);
244	      setCurrentView(TopologyViewLevel.DEPLOYMENTS);
245	    }
246	    if (needsUpdate && TopologyViewLevel.NODES === visualizationLevel) {
247	      const groupedNodes = groupNodesByZones(nodes);
248	      const dataModel = groupedNodes.map(generateNodesInZone);
249	      const flattenedDataModel = _.flatten(dataModel);
250	      const children = flattenedDataModel
251	        .filter((item) => item.type === 'group')
252	        .map((item) => item.id);
253	      const storageClusterGroup = generateStorageClusterGroup(storageCluster);
254	      storageClusterGroup.children = children;
255	      const data = {
256	        nodes: [storageClusterGroup, ...flattenedDataModel],
257	      };
258	      const model = {
259	        graph: {
260	          visualizationLevel,
261	          id: 'g1',
262	          type: 'graph',
263	          layout: 'Cola',
264	        },
265	        ...data,
266	      };
267	      controller.fromModel(model, false);
268	      setCurrentView(TopologyViewLevel.NODES);
269	    }
270	  }, [
271	    activeNode,
272	    controller,
273	    currentView,
274	    deployments,
275	    nodeDeploymentMap,
276	    nodes,
277	    storageCluster,
278	    visualizationLevel,
279	  ]);
280	
281	  React.useEffect(() => {
282	    const currentModel = controller.toModel();
283	    const graphNodes = currentModel.nodes;
284	    let requiresUpdate = false;
285	
286	    const existingIDs = graphNodes.map((node) => node.id);
287	    const inViewResources = [...nodes, ...deployments, storageCluster];
288	    const inViewUIDs = inViewResources.map(getUID);
289	    const childUIDsToBeRemoved = [];
290	
291	    // Handle deletion of Resources
292	    const filtererdGraphNodes = graphNodes.filter((node) => {
293	      if (node.type !== 'group' && !inViewUIDs.includes(node.id)) {
294	        childUIDsToBeRemoved.push(node.id);
295	        return false;
296	      }
297	      return true;
298	    });
299	    if (childUIDsToBeRemoved.length > 0) {
300	      requiresUpdate = true;
301	      filtererdGraphNodes.forEach((node) => {
302	        if (node.type === 'group') {
303	          node.children = node.children.filter(
304	            (value) => !childUIDsToBeRemoved.includes(value)
305	          );
306	        }
307	      });
308	    }
309	    // Handle update of Resources
310	    filtererdGraphNodes.forEach((node) => {
311	      const resource = inViewResources.find(
312	        (n) => n.metadata.uid === getUID(node?.data?.resource)
313	      );
314	      if (!_.isEqual(node.data.resource, resource)) {
315	        requiresUpdate = true;
316	        node.data.resource = resource;
317	      }
318	    });
319	
320	    // Handle addition of Resources
321	    const newResourcesUIDs = _.intersection(existingIDs, inViewUIDs);
322	    const newResources = inViewResources.filter((resource) =>
323	      newResourcesUIDs.includes(getUID(resource))
324	    );
325	
326	    const newNodes: NodeKind[] = newResources.filter(
327	      (resource) => resource.kind === NodeModel.kind
328	    ) as any;
329	    const newDeployments = newResources.filter(
330	      (resource) => resource.kind === DeploymentModel.kind
331	    );
332	
333	    const existingZones = graphNodes
334	      .filter((n) => n.type === 'group' && _.has(n.data, 'zone'))
335	      .map((n) => n.data.zone);
336	
337	    const [newNodesInNewZones, newNodesInExistingZones] = newNodes.reduce(
338	      (acc, node) => {
339	        const newZonesArray = acc[0];
340	        const oldZonesArray = acc[1];
341	        if (existingZones.includes(getTopologyDomain(node))) {
342	          oldZonesArray.push(node);
343	        } else {
344	          newZonesArray.push(node);
345	        }
346	        return [newZonesArray, oldZonesArray];
347	      },
348	      [[], []]
349	    );
350	    const newZoneAndNodeGroup =
351	      newNodesInNewZones.length > 0
352	        ? generateNodesInZone(newNodesInNewZones)
353	        : [];
354	
355	    const addedNodes = [];
356	    if (newNodesInExistingZones.length > 0) {
357	      requiresUpdate = true;
358	      newNodesInExistingZones.forEach((newNode) => {
359	        const nodeModel = createNode({
360	          id: getUID(newNode),
361	          label: getName(newNode),
362	          labelPosition: LabelPosition.bottom,
363	          badge: NodeModel.abbr,
364	          shape: NodeShape.ellipse,
365	          showStatusDecorator: true,
366	          showDecorators: true,
367	          resource: newNode,
368	        });
369	        addedNodes.push(nodeModel);
370	        filtererdGraphNodes.forEach((n) =>
371	          n.group && n.data.zone === getTopologyDomain(newNode)
372	            ? n.children.push(nodeModel.id)
373	            : _.noop
374	        );
375	      });
376	    }
377	
378	    const newDeploymentNodes = newDeployments.map((deployment) => {
379	      const deploymentModel = createNode({
380	        id: getUID(deployment),
381	        label: getName(deployment),
382	        labelPosition: LabelPosition.bottom,
383	        badge: DeploymentModel.abbr,
384	        showStatusDecorator: true,
385	        resource: deployment,
386	      });
387	      return deploymentModel;
388	    });
389	
390	    if (newDeploymentNodes.length > 0) {
391	      requiresUpdate = true;
392	      newDeployments.forEach((deployment) => {
393	        Object.entries(nodeDeploymentMap).forEach(([node, nodeDeployments]) => {
394	          const hasDeployment = !_.isUndefined(
395	            nodeDeployments.find((d) => getUID(d) === getUID(deployment))
396	          );
397	          if (hasDeployment) {
398	            filtererdGraphNodes.forEach((gNode) => {
399	              if (gNode.label === node) {
400	                gNode.children.push(getUID(deployment));
401	              }
402	            });
403	          }
404	        });
405	      });
406	    }
407	
408	    const updatedModel = {
409	      ...currentModel,
410	      nodes: [...filtererdGraphNodes, ...newZoneAndNodeGroup, ...addedNodes],
411	    };
412	    if (requiresUpdate) {
413	      controller.fromModel(updatedModel);
414	    }
415	  }, [controller, nodes, deployments, nodeDeploymentMap, storageCluster]);
416	
417	  const toggleVisualizationLevel = React.useCallback(
418	    () => controller.fireEvent(STEP_TO_CLUSTER),
419	    [controller]
420	  );
421	
422	  return (
423	    <TopologyView
424	      controlBar={
425	        <TopologyControlBar
426	          data-test="topology-control-bar"
427	          controlButtons={createTopologyControlButtons({
428	            ...defaultControlButtonsOptions,
429	            zoomInTip: t('Zoom in'),
430	            zoomInCallback: () => {
431	              controller && controller.getGraph().scaleBy(ZOOM_IN);
432	            },
433	            zoomOutTip: t('Zoom out'),
434	            zoomOutCallback: () => {
435	              controller && controller.getGraph().scaleBy(ZOOM_OUT);
436	            },
437	            fitToScreenTip: t('Fit to screen'),
438	            fitToScreenCallback: () => {
439	              controller && controller.getGraph().fit(100);
440	            },
441	            resetViewTip: t('Reset view'),
442	            resetViewCallback: () => {
443	              if (controller) {
444	                controller.getGraph().reset();
445	                controller.getGraph().layout();
446	              }
447	            },
448	            legend: false,
449	          })}
450	        />
451	      }
452	      sideBar={<Sidebar onClose={onCloseSideBar} isExpanded={isSideBarOpen} />}
453	      sideBarResizable={true}
454	      minSideBarSize="400px"
455	      sideBarOpen={isSideBarOpen}
456	    >
457	      {currentView === TopologyViewLevel.DEPLOYMENTS && (
458	        <BackButton onClick={toggleVisualizationLevel} />
459	      )}
460	      <MessageButton />
461	      <VisualizationSurface state={{ selectedIds }} />
462	    </TopologyView>
463	  );
464	};
465	
466	const Error = ({ error }) => <>{error}</>;
467	
468	const Topology: React.FC = () => {
469	  const { odfNamespace, isODFNsLoaded, odfNsLoadError } =
470	    useODFNamespaceSelector();
471	
472	  const [controller, setController] = React.useState<Visualization>(null);
473	  const [visualizationLevel, setVisualizationLevel] =
474	    React.useState<TopologyViewLevel>(TopologyViewLevel.NODES);
475	  const [activeItemsUID, setActiveItemsUID] = React.useState<string[]>([]);
476	  const [activeItem, setActiveItem] = React.useState<string>('');
477	  const [activeNode, setActiveNode] = React.useState('');
478	  const [selectedElement, setSelectedElement] =
479	    React.useState<GraphElement>(null);
480	
481	  const [nodes, nodesLoaded, nodesError] =
482	    useK8sWatchResource<NodeKind[]>(nodeResource);
483	
484	  const [storageClusters, storageClustersLoaded, storageClustersError] =
485	    useK8sWatchResource<StorageClusterKind[]>(storageClusterResource);
486	
487	  const [deployments, deploymentsLoaded, deploymentsError] =
488	    useSafeK8sWatchResource<DeploymentKind[]>(odfDeploymentsResource);
489	
490	  const [pods, podsLoaded, podsError] =
491	    useSafeK8sWatchResource<PodKind[]>(odfPodsResource);
492	
493	  const [statefulSets, statefulSetLoaded, statefulSetError] =
494	    useSafeK8sWatchResource<K8sResourceCommon[]>(odfStatefulSetResource);
495	
496	  const [replicaSets, replicaSetsLoaded, replicaSetsError] =
497	    useSafeK8sWatchResource<K8sResourceCommon[]>(odfReplicaSetResource);
498	
499	  const [daemonSets, daemonSetsLoaded, daemonSetError] =
500	    useSafeK8sWatchResource<K8sResourceCommon[]>(odfDaemonSetResource);
501	
502	  // ToDo (epic 4422): This will work as Internal mode cluster will only be created in ODF install namespace.
503	  // Still, make this generic so that this works even if it gets created in a different namespace.
504	  const storageCluster: StorageClusterKind = getStorageClusterInNs(
505	    storageClusters,
506	    odfNamespace
507	  );
508	
509	  const storageLabel = cephStorageLabel(odfNamespace);
510	  const odfNodes = nodes.filter((node) =>
511	    _.has(node.metadata.labels, storageLabel)
512	  );
513	
514	  const memoizedNodes = useDeepCompareMemoize(odfNodes, true);
515	  const memoizedDeployments = useDeepCompareMemoize(deployments, true);
516	  const memoizedPods = useDeepCompareMemoize(pods, true);
517	  const memoizedStatefulSets = useDeepCompareMemoize(statefulSets, true);
518	  const memoizedReplicaSets = useDeepCompareMemoize(replicaSets, true);
519	  const memoizedDaemonSets = useDeepCompareMemoize(daemonSets, true);
520	
521	  const nodeDeploymentMap = React.useMemo(
522	    () =>
523	      generateNodeDeploymentsMap(
524	        memoizedNodes,
525	        memoizedPods,
526	        memoizedDeployments,
527	        ...memoizedReplicaSets,
528	        ...memoizedDaemonSets,
529	        ...memoizedStatefulSets,
530	        ...memoizedDeployments
531	      ),
532	    [
533	      memoizedDaemonSets,
534	      memoizedDeployments,
535	      memoizedNodes,
536	      memoizedPods,
537	      memoizedReplicaSets,
538	      memoizedStatefulSets,
539	    ]
540	  );
541	
542	  const onStepInto = (args) => {
543	    const nodeName = args.label;
544	    setActiveNode(nodeName);
545	    setVisualizationLevel(TopologyViewLevel.DEPLOYMENTS);
546	  };
547	
548	  const onStepOut = () => {
549	    setActiveNode('');
550	    setVisualizationLevel(TopologyViewLevel.NODES);
551	  };
552	
553	  React.useEffect(() => {
554	    const temp = new Visualization();
555	    temp.registerLayoutFactory(defaultLayoutFactory);
556	    temp.registerComponentFactory(stylesComponentFactory as any);
557	    temp.addEventListener(STEP_INTO_EVENT, onStepInto);
558	    temp.addEventListener(STEP_TO_CLUSTER, onStepOut);
559	    setController(temp);
560	
561	    return () => {
562	      temp.removeEventListener(STEP_INTO_EVENT, onStepInto);
563	      temp.removeEventListener(STEP_TO_CLUSTER, onStepOut);
564	    };
565	  }, []);
566	
567	  const loading =
568	    !nodesLoaded ||
569	    !storageClustersLoaded ||
570	    !deploymentsLoaded ||
571	    !podsLoaded ||
572	    !statefulSetLoaded ||
573	    !replicaSetsLoaded ||
574	    !daemonSetsLoaded ||
575	    !isODFNsLoaded;
576	
577	  const zones = memoizedNodes.map(getTopologyDomain);
578	
579	  const topologyDataContextData = React.useMemo(() => {
580	    return {
581	      nodes: memoizedNodes,
582	      storageCluster: storageCluster,
583	      zones,
584	      deployments: memoizedDeployments,
585	      visualizationLevel: visualizationLevel,
586	      activeNode,
587	      setActiveNode,
588	      nodeDeploymentMap,
589	      selectedElement,
590	      setSelectedElement: setSelectedElement as any,
591	    };
592	  }, [
593	    memoizedNodes,
594	    storageCluster,
595	    zones,
596	    memoizedDeployments,
597	    visualizationLevel,
598	    activeNode,
599	    setActiveNode,
600	    nodeDeploymentMap,
601	    selectedElement,
602	    setSelectedElement,
603	  ]);
604	
605	  const topologySearchContextData = React.useMemo(() => {
606	    return { activeItemsUID, setActiveItemsUID, activeItem, setActiveItem };
607	  }, [activeItemsUID, setActiveItemsUID, activeItem, setActiveItem]);
608	
609	  return (
610	    <TopologyDataContext.Provider value={topologyDataContextData}>
611	      <TopologySearchContext.Provider value={topologySearchContextData}>
612	        <VisualizationProvider controller={controller}>
613	          <div className="odf__topology-view" id="odf-topology">
614	            <TopologyTopBar />
615	            <HandleErrorAndLoading
616	              loading={loading}
617	              error={
618	                storageClustersError ||
619	                nodesError ||
620	                deploymentsError ||
621	                podsError ||
622	                replicaSetsError ||
623	                daemonSetError ||
624	                statefulSetError ||
625	                odfNsLoadError
626	              }
627	              ErrorMessage={Error}
628	            >
629	              <TopologyViewComponent />
630	            </HandleErrorAndLoading>
631	          </div>
632	        </VisualizationProvider>
633	      </TopologySearchContext.Provider>
634	    </TopologyDataContext.Provider>
635	  );
636	};
637	
638	type TopologyViewErrorMessageProps = {
639	  isExternalMode?: boolean;
640	  isInternalMode?: boolean;
641	};
642	
643	const TopologyViewErrorMessage: React.FC<TopologyViewErrorMessageProps> = ({
644	  isExternalMode,
645	  isInternalMode,
646	}) => {
647	  const { t } = useCustomTranslation();
648	
649	  const { isNsSafe } = useODFNamespaceSelector();
650	
651	  // If external mode cluster exists, we do not allow internal mode cluster creation (in case of multiple StorageSystem support)
652	  const hideCreateSSOption = (isExternalMode && !isInternalMode) || !isNsSafe;
653	  return (
654	    <EmptyState>
655	      <EmptyStateIcon icon={TopologyIcon} />
656	      <Title headingLevel="h4" size="lg">
657	        {isExternalMode
658	          ? t('Topology view is not supported for External mode')
659	          : t('No StorageCluster found')}
660	      </Title>
661	      <EmptyStateBody>
662	        {!hideCreateSSOption &&
663	          t('Set up a storage cluster to view the topology')}
664	      </EmptyStateBody>
665	      {!hideCreateSSOption && (
666	        <Link to={CREATE_SS_PAGE_URL}>{t('Create storage system')} </Link>
667	      )}
668	    </EmptyState>
669	  );
670	};
671	
672	const TopologyWithErrorHandler: React.FC = () => {
673	  const { systemFlags } = useODFSystemFlagsSelector();
674	
675	  const isCephAvailable = hasAnyCeph(systemFlags);
676	  const isMCGStandalone = hasAnyNoobaaStandalone(systemFlags);
677	  const isExternalMode = hasAnyExternalOCS(systemFlags);
678	  const isInternalMode = hasAnyInternalOCS(systemFlags);
