150	const TopologyViewComponent: React.FC = () => {
151	  const { t } = useCustomTranslation();
152	  const [selectedIds, setSelectedIds] = React.useState<string[]>([]);
153	  const [currentView, setCurrentView] = React.useState(TopologyViewLevel.NODES);
154	  const controller = useVisualizationController();
155	
156	  const lastNode = React.useRef<string>();
157	
158	  const [isSideBarOpen, setSideBarOpen] = React.useState(false);
159	  const {
160	    nodes,
161	    storageCluster,
162	    deployments,
163	    visualizationLevel,
164	    activeNode,
165	    nodeDeploymentMap,
166	    setSelectedElement,
167	  } = React.useContext(TopologyDataContext);
168	
169	  const onCloseSideBar = React.useCallback(() => {
170	    setSideBarOpen(false);
171	    setSelectedIds([]);
172	  }, []);
173	
174	  React.useEffect(() => {
175	    const selectionHandler = (ids: string[]) => {
176	      const element = controller.getElementById(ids[0]);
177	      if (!!element && !_.has(element.getData(), 'zone')) {
178	        setSelectedElement(element);
179	        setSelectedIds([ids[0]]);
180	        setSideBarOpen(true);
181	      }
182	    };
183	    controller.addEventListener(SELECTION_EVENT, selectionHandler);
184	    controller.addEventListener(STEP_INTO_EVENT, onCloseSideBar);
185	    controller.addEventListener(STEP_TO_CLUSTER, onCloseSideBar);
186	    return () => {
187	      controller.removeEventListener(SELECTION_EVENT, selectionHandler);
188	      controller.removeEventListener(STEP_INTO_EVENT, onCloseSideBar);
189	      controller.removeEventListener(STEP_TO_CLUSTER, onCloseSideBar);
190	    };
191	  }, [controller, setSelectedElement, onCloseSideBar]);
192	
193	  React.useEffect(() => {
194	    const groupedNodes = groupNodesByZones(nodes);
195	    const dataModel = groupedNodes.map(generateNodesInZone);
196	    const flattenedDataModel = _.flatten(dataModel);
197	    const children = flattenedDataModel
198	      .filter((item) => item.type === 'group')
199	      .map((item) => item.id);
200	    const storageClusterGroup = generateStorageClusterGroup(storageCluster);
201	    storageClusterGroup.children = children;
202	    const data = {
203	      nodes: [storageClusterGroup, ...flattenedDataModel],
204	    };
205	    const model = {
206	      graph: {
207	        id: 'g1',
208	        type: 'graph',
209	        layout: 'Cola',
210	      },
211	      ...data,
212	    };
213	    controller.fromModel(model);
214	    // To handle initial render only, keeping array empty
215	    // eslint-disable-next-line react-hooks/exhaustive-deps
216	  }, []);
217	
218	  React.useEffect(() => {
219	    const currentNode = activeNode
220	      ? nodes.find((node) => getName(node) === activeNode)
221	      : nodes[0];
222	
223	    const needsUpdate =
224	      currentView !== visualizationLevel || activeNode !== lastNode.current;
225	    if (activeNode !== lastNode.current) {
226	      lastNode.current = activeNode;
227	    }
228	
229	    if (needsUpdate && TopologyViewLevel.DEPLOYMENTS === visualizationLevel) {
230	      const dataModel = generateDeploymentsInNodes(
231	        currentNode,
232	        nodeDeploymentMap
233	      );
234	      const model = {
235	        graph: {
236	          visualizationLevel,
237	          id: 'g1',
238	          type: 'graph',
239	          layout: 'Cola',
240	        },
241	        nodes: dataModel,
242	      };
243	      controller.fromModel(model, false);
244	      setCurrentView(TopologyViewLevel.DEPLOYMENTS);
245	    }
246	    if (needsUpdate && TopologyViewLevel.NODES === visualizationLevel) {
247	      const groupedNodes = groupNodesByZones(nodes);
248	      const dataModel = groupedNodes.map(generateNodesInZone);
249	      const flattenedDataModel = _.flatten(dataModel);
250	      const children = flattenedDataModel
251	        .filter((item) => item.type === 'group')
252	        .map((item) => item.id);
253	      const storageClusterGroup = generateStorageClusterGroup(storageCluster);
254	      storageClusterGroup.children = children;
255	      const data = {
256	        nodes: [storageClusterGroup, ...flattenedDataModel],
257	      };
258	      const model = {
259	        graph: {
260	          visualizationLevel,
261	          id: 'g1',
262	          type: 'graph',
263	          layout: 'Cola',
264	        },
265	        ...data,
266	      };
267	      controller.fromModel(model, false);
268	      setCurrentView(TopologyViewLevel.NODES);
269	    }
270	  }, [
271	    activeNode,
272	    controller,
273	    currentView,
274	    deployments,
275	    nodeDeploymentMap,
276	    nodes,
277	    storageCluster,
278	    visualizationLevel,
279	  ]);
280	
281	  React.useEffect(() => {
282	    const currentModel = controller.toModel();
283	    const graphNodes = currentModel.nodes;
284	    let requiresUpdate = false;
285	
286	    const existingIDs = graphNodes.map((node) => node.id);
287	    const inViewResources = [...nodes, ...deployments, storageCluster];
288	    const inViewUIDs = inViewResources.map(getUID);
289	    const childUIDsToBeRemoved = [];
290	
291	    // Handle deletion of Resources
292	    const filtererdGraphNodes = graphNodes.filter((node) => {
293	      if (node.type !== 'group' && !inViewUIDs.includes(node.id)) {
294	        childUIDsToBeRemoved.push(node.id);
295	        return false;
296	      }
297	      return true;
298	    });
299	    if (childUIDsToBeRemoved.length > 0) {
300	      requiresUpdate = true;
301	      filtererdGraphNodes.forEach((node) => {
302	        if (node.type === 'group') {
303	          node.children = node.children.filter(
304	            (value) => !childUIDsToBeRemoved.includes(value)
305	          );
306	        }
307	      });
308	    }
309	    // Handle update of Resources
310	    filtererdGraphNodes.forEach((node) => {
311	      const resource = inViewResources.find(
312	        (n) => n.metadata.uid === getUID(node?.data?.resource)
313	      );
314	      if (!_.isEqual(node.data.resource, resource)) {
315	        requiresUpdate = true;
316	        node.data.resource = resource;
317	      }
318	    });
319	
320	    // Handle addition of Resources
321	    const newResourcesUIDs = _.intersection(existingIDs, inViewUIDs);
322	    const newResources = inViewResources.filter((resource) =>
323	      newResourcesUIDs.includes(getUID(resource))
324	    );
325	
326	    const newNodes: NodeKind[] = newResources.filter(
327	      (resource) => resource.kind === NodeModel.kind
328	    ) as any;
329	    const newDeployments = newResources.filter(
330	      (resource) => resource.kind === DeploymentModel.kind
331	    );
332	
333	    const existingZones = graphNodes
334	      .filter((n) => n.type === 'group' && _.has(n.data, 'zone'))
335	      .map((n) => n.data.zone);
336	
337	    const [newNodesInNewZones, newNodesInExistingZones] = newNodes.reduce(
338	      (acc, node) => {
339	        const newZonesArray = acc[0];
340	        const oldZonesArray = acc[1];
341	        if (existingZones.includes(getTopologyDomain(node))) {
342	          oldZonesArray.push(node);
343	        } else {
344	          newZonesArray.push(node);
345	        }
346	        return [newZonesArray, oldZonesArray];
347	      },
348	      [[], []]
349	    );
350	    const newZoneAndNodeGroup =
351	      newNodesInNewZones.length > 0
352	        ? generateNodesInZone(newNodesInNewZones)
353	        : [];
354	
355	    const addedNodes = [];
356	    if (newNodesInExistingZones.length > 0) {
357	      requiresUpdate = true;
358	      newNodesInExistingZones.forEach((newNode) => {
359	        const nodeModel = createNode({
360	          id: getUID(newNode),
361	          label: getName(newNode),
362	          labelPosition: LabelPosition.bottom,
363	          badge: NodeModel.abbr,
364	          shape: NodeShape.ellipse,
365	          showStatusDecorator: true,
366	          showDecorators: true,
367	          resource: newNode,
368	        });
369	        addedNodes.push(nodeModel);
370	        filtererdGraphNodes.forEach((n) =>
371	          n.group && n.data.zone === getTopologyDomain(newNode)
372	            ? n.children.push(nodeModel.id)
373	            : _.noop
374	        );
375	      });
376	    }
377	
378	    const newDeploymentNodes = newDeployments.map((deployment) => {
379	      const deploymentModel = createNode({
380	        id: getUID(deployment),
381	        label: getName(deployment),
382	        labelPosition: LabelPosition.bottom,
383	        badge: DeploymentModel.abbr,
384	        showStatusDecorator: true,
385	        resource: deployment,
386	      });
387	      return deploymentModel;
388	    });
389	
390	    if (newDeploymentNodes.length > 0) {
391	      requiresUpdate = true;
392	      newDeployments.forEach((deployment) => {
