369	        addedNodes.push(nodeModel);
370	        filtererdGraphNodes.forEach((n) =>
371	          n.group && n.data.zone === getTopologyDomain(newNode)
372	            ? n.children.push(nodeModel.id)
373	            : _.noop
374	        );
375	      });
376	    }
377	
378	    const newDeploymentNodes = newDeployments.map((deployment) => {
379	      const deploymentModel = createNode({
380	        id: getUID(deployment),
381	        label: getName(deployment),
382	        labelPosition: LabelPosition.bottom,
383	        badge: DeploymentModel.abbr,
384	        showStatusDecorator: true,
385	        resource: deployment,
386	      });
387	      return deploymentModel;
388	    });
389	
390	    if (newDeploymentNodes.length > 0) {
391	      requiresUpdate = true;
392	      newDeployments.forEach((deployment) => {
393	        Object.entries(nodeDeploymentMap).forEach(([node, nodeDeployments]) => {
394	          const hasDeployment = !_.isUndefined(
395	            nodeDeployments.find((d) => getUID(d) === getUID(deployment))
396	          );
397	          if (hasDeployment) {
398	            filtererdGraphNodes.forEach((gNode) => {
399	              if (gNode.label === node) {
400	                gNode.children.push(getUID(deployment));
401	              }
402	            });
403	          }
404	        });
405	      });
406	    }
407	
408	    const updatedModel = {
409	      ...currentModel,
410	      nodes: [...filtererdGraphNodes, ...newZoneAndNodeGroup, ...addedNodes],
411	    };
412	    if (requiresUpdate) {
413	      controller.fromModel(updatedModel);
414	    }
415	  }, [controller, nodes, deployments, nodeDeploymentMap, storageCluster]);
416	
417	  const toggleVisualizationLevel = React.useCallback(
418	    () => controller.fireEvent(STEP_TO_CLUSTER),
419	    [controller]
420	  );
421	
422	  return (
423	    <TopologyView
424	      controlBar={
425	        <TopologyControlBar
426	          data-test="topology-control-bar"
427	          controlButtons={createTopologyControlButtons({
428	            ...defaultControlButtonsOptions,
429	            zoomInTip: t('Zoom in'),
430	            zoomInCallback: () => {
431	              controller && controller.getGraph().scaleBy(ZOOM_IN);
432	            },
433	            zoomOutTip: t('Zoom out'),
434	            zoomOutCallback: () => {
435	              controller && controller.getGraph().scaleBy(ZOOM_OUT);
436	            },
437	            fitToScreenTip: t('Fit to screen'),
438	            fitToScreenCallback: () => {
439	              controller && controller.getGraph().fit(100);
440	            },
441	            resetViewTip: t('Reset view'),
442	            resetViewCallback: () => {
443	              if (controller) {
444	                controller.getGraph().reset();
445	                controller.getGraph().layout();
446	              }
447	            },
448	            legend: false,
449	          })}
450	        />
451	      }
452	      sideBar={<Sidebar onClose={onCloseSideBar} isExpanded={isSideBarOpen} />}
453	      sideBarResizable={true}
454	      minSideBarSize="400px"
455	      sideBarOpen={isSideBarOpen}
456	    >
457	      {currentView === TopologyViewLevel.DEPLOYMENTS && (
458	        <BackButton onClick={toggleVisualizationLevel} />
459	      )}
460	      <MessageButton />
461	      <VisualizationSurface state={{ selectedIds }} />
462	    </TopologyView>
463	  );
464	};
465	
466	const Error = ({ error }) => <>{error}</>;
467	
468	const Topology: React.FC = () => {
469	  const { odfNamespace, isODFNsLoaded, odfNsLoadError } =
470	    useODFNamespaceSelector();
471	
472	  const [controller, setController] = React.useState<Visualization>(null);
473	  const [visualizationLevel, setVisualizationLevel] =
474	    React.useState<TopologyViewLevel>(TopologyViewLevel.NODES);
475	  const [activeItemsUID, setActiveItemsUID] = React.useState<string[]>([]);
476	  const [activeItem, setActiveItem] = React.useState<string>('');
477	  const [activeNode, setActiveNode] = React.useState('');
478	  const [selectedElement, setSelectedElement] =
479	    React.useState<GraphElement>(null);
480	
481	  const [nodes, nodesLoaded, nodesError] =
482	    useK8sWatchResource<NodeKind[]>(nodeResource);
483	
484	  const [storageClusters, storageClustersLoaded, storageClustersError] =
485	    useK8sWatchResource<StorageClusterKind[]>(storageClusterResource);
486	
487	  const [deployments, deploymentsLoaded, deploymentsError] =
488	    useSafeK8sWatchResource<DeploymentKind[]>(odfDeploymentsResource);
489	
490	  const [pods, podsLoaded, podsError] =
491	    useSafeK8sWatchResource<PodKind[]>(odfPodsResource);
492	
493	  const [statefulSets, statefulSetLoaded, statefulSetError] =
494	    useSafeK8sWatchResource<K8sResourceCommon[]>(odfStatefulSetResource);
495	
496	  const [replicaSets, replicaSetsLoaded, replicaSetsError] =
497	    useSafeK8sWatchResource<K8sResourceCommon[]>(odfReplicaSetResource);
498	
499	  const [daemonSets, daemonSetsLoaded, daemonSetError] =
500	    useSafeK8sWatchResource<K8sResourceCommon[]>(odfDaemonSetResource);
501	
502	  // ToDo (epic 4422): This will work as Internal mode cluster will only be created in ODF install namespace.
503	  // Still, make this generic so that this works even if it gets created in a different namespace.
504	  const storageCluster: StorageClusterKind = getStorageClusterInNs(
505	    storageClusters,
506	    odfNamespace
507	  );
508	
509	  const storageLabel = cephStorageLabel(odfNamespace);
510	  const odfNodes = nodes.filter((node) =>
511	    _.has(node.metadata.labels, storageLabel)
512	  );
513	
514	  const memoizedNodes = useDeepCompareMemoize(odfNodes, true);
515	  const memoizedDeployments = useDeepCompareMemoize(deployments, true);
516	  const memoizedPods = useDeepCompareMemoize(pods, true);
517	  const memoizedStatefulSets = useDeepCompareMemoize(statefulSets, true);
518	  const memoizedReplicaSets = useDeepCompareMemoize(replicaSets, true);
519	  const memoizedDaemonSets = useDeepCompareMemoize(daemonSets, true);
520	
521	  const nodeDeploymentMap = React.useMemo(
522	    () =>
523	      generateNodeDeploymentsMap(
524	        memoizedNodes,
525	        memoizedPods,
526	        memoizedDeployments,
527	        ...memoizedReplicaSets,
528	        ...memoizedDaemonSets,
529	        ...memoizedStatefulSets,
530	        ...memoizedDeployments
531	      ),
532	    [
533	      memoizedDaemonSets,
534	      memoizedDeployments,
535	      memoizedNodes,
536	      memoizedPods,
537	      memoizedReplicaSets,
538	      memoizedStatefulSets,
539	    ]
540	  );
541	
542	  const onStepInto = (args) => {
543	    const nodeName = args.label;
544	    setActiveNode(nodeName);
545	    setVisualizationLevel(TopologyViewLevel.DEPLOYMENTS);
546	  };
547	
548	  const onStepOut = () => {
549	    setActiveNode('');
550	    setVisualizationLevel(TopologyViewLevel.NODES);
551	  };
552	
553	  React.useEffect(() => {
554	    const temp = new Visualization();
555	    temp.registerLayoutFactory(defaultLayoutFactory);
556	    temp.registerComponentFactory(stylesComponentFactory as any);
557	    temp.addEventListener(STEP_INTO_EVENT, onStepInto);
558	    temp.addEventListener(STEP_TO_CLUSTER, onStepOut);
559	    setController(temp);
560	
561	    return () => {
562	      temp.removeEventListener(STEP_INTO_EVENT, onStepInto);
563	      temp.removeEventListener(STEP_TO_CLUSTER, onStepOut);
564	    };
565	  }, []);
566	
567	  const loading =
568	    !nodesLoaded ||
569	    !storageClustersLoaded ||
570	    !deploymentsLoaded ||
571	    !podsLoaded ||
572	    !statefulSetLoaded ||
573	    !replicaSetsLoaded ||
574	    !daemonSetsLoaded ||
575	    !isODFNsLoaded;
576	
577	  const zones = memoizedNodes.map(getTopologyDomain);
578	
579	  const topologyDataContextData = React.useMemo(() => {
580	    return {
581	      nodes: memoizedNodes,
582	      storageCluster: storageCluster,
583	      zones,
584	      deployments: memoizedDeployments,
585	      visualizationLevel: visualizationLevel,
586	      activeNode,
587	      setActiveNode,
588	      nodeDeploymentMap,
589	      selectedElement,
590	      setSelectedElement: setSelectedElement as any,
591	    };
592	  }, [
593	    memoizedNodes,
594	    storageCluster,
595	    zones,
596	    memoizedDeployments,
597	    visualizationLevel,
598	    activeNode,
599	    setActiveNode,
600	    nodeDeploymentMap,
601	    selectedElement,
602	    setSelectedElement,
603	  ]);
604	
605	  const topologySearchContextData = React.useMemo(() => {
606	    return { activeItemsUID, setActiveItemsUID, activeItem, setActiveItem };
607	  }, [activeItemsUID, setActiveItemsUID, activeItem, setActiveItem]);
608	
609	  return (
610	    <TopologyDataContext.Provider value={topologyDataContextData}>
611	      <TopologySearchContext.Provider value={topologySearchContextData}>
612	        <VisualizationProvider controller={controller}>
613	          <div className="odf__topology-view" id="odf-topology">
614	            <TopologyTopBar />
615	            <HandleErrorAndLoading
616	              loading={loading}
617	              error={
618	                storageClustersError ||
619	                nodesError ||
620	                deploymentsError ||
621	                podsError ||
622	                replicaSetsError ||
623	                daemonSetError ||
624	                statefulSetError ||
625	                odfNsLoadError
626	              }
627	              ErrorMessage={Error}
628	            >
629	              <TopologyViewComponent />
630	            </HandleErrorAndLoading>
631	          </div>
632	        </VisualizationProvider>
633	      </TopologySearchContext.Provider>
634	    </TopologyDataContext.Provider>
635	  );
636	};
637	
638	type TopologyViewErrorMessageProps = {
639	  isExternalMode?: boolean;
640	  isInternalMode?: boolean;
641	};
642	
643	const TopologyViewErrorMessage: React.FC<TopologyViewErrorMessageProps> = ({
644	  isExternalMode,
645	  isInternalMode,
646	}) => {
647	  const { t } = useCustomTranslation();
648	
649	  const { isNsSafe } = useODFNamespaceSelector();
650	
651	  // If external mode cluster exists, we do not allow internal mode cluster creation (in case of multiple StorageSystem support)
652	  const hideCreateSSOption = (isExternalMode && !isInternalMode) || !isNsSafe;
653	  return (
654	    <EmptyState
655	      icon={TopologyIcon}
656	      headingLevel="h4"
657	      titleText={
658	        isExternalMode
659	          ? t('Topology view is not supported for External mode')
660	          : t('No StorageCluster found')
661	      }
662	    >
663	      <EmptyStateBody>
664	        {!hideCreateSSOption &&
665	          t('Set up a storage cluster to view the topology')}
666	      </EmptyStateBody>
667	      {!hideCreateSSOption && (
668	        <EmptyStateFooter>
669	          <EmptyStateActions>
670	            <Link to={CREATE_SS_PAGE_URL}>{t('Create storage system')} </Link>
671	          </EmptyStateActions>
672	        </EmptyStateFooter>
673	      )}
674	    </EmptyState>
675	  );
676	};
677	
678	const TopologyWithErrorHandler: React.FC = () => {
679	  const { systemFlags } = useODFSystemFlagsSelector();
680	
681	  const isCephAvailable = hasAnyCeph(systemFlags);
682	  const isMCGStandalone = hasAnyNoobaaStandalone(systemFlags);
683	  const isExternalMode = hasAnyExternalOCS(systemFlags);
684	  const isInternalMode = hasAnyInternalOCS(systemFlags);
685	
686	  const showDashboard = (isCephAvailable || isMCGStandalone) && isInternalMode;
687	
688	  return showDashboard ? (
689	    <Topology />
690	  ) : (
691	    <TopologyViewErrorMessage
692	      isExternalMode={isExternalMode}
693	      isInternalMode={isInternalMode}
694	    />
695	  );
696	};
697	
698	export default TopologyWithErrorHandler;

